-- -- confirm_vendor_order: atomic warehouse -> vendor stock transfer ----
-- Locks every affected product_inventory row (ordered by product_id to
-- avoid deadlocks against concurrent confirmations), verifies each item has
-- enough warehouse stock (blocks the whole order if not -- per business
-- rule, no overdraft), then decrements product_inventory and upserts
-- vendor_stock for every line item in one transaction. Logs both
-- stock_movements (reason='vendor_dispatch') and vendor_stock_movements
-- (reason='dispatch').
CREATE OR REPLACE FUNCTION "public"."confirm_vendor_order"(
    "p_vendor_order_id" "uuid",
    "p_created_by" "uuid" DEFAULT NULL
) RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_order record;
  v_item record;
  v_prev_wh integer;
  v_new_wh integer;
  v_prev_vendor integer;
  v_new_vendor integer;
BEGIN
  SELECT id, store_id, vendor_id, status INTO v_order
  FROM public.vendor_orders
  WHERE id = p_vendor_order_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Vendor order % not found', p_vendor_order_id;
  END IF;

  IF v_order.status <> 'draft' THEN
    RAISE EXCEPTION 'Vendor order % is not in draft status (current: %)', p_vendor_order_id, v_order.status;
  END IF;

  FOR v_item IN
    SELECT product_id, variant_id, quantity, vendor_tp
    FROM public.vendor_order_items
    WHERE vendor_order_id = p_vendor_order_id
    ORDER BY product_id, variant_id
  LOOP
    SELECT quantity_available INTO v_prev_wh
    FROM public.product_inventory
    WHERE product_id = v_item.product_id
      AND variant_id IS NOT DISTINCT FROM v_item.variant_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No warehouse inventory row for product % / variant %', v_item.product_id, v_item.variant_id;
    END IF;

    IF v_prev_wh < v_item.quantity THEN
      RAISE EXCEPTION 'Insufficient warehouse stock for product %: have %, need %', v_item.product_id, v_prev_wh, v_item.quantity;
    END IF;

    v_new_wh := v_prev_wh - v_item.quantity;

    UPDATE public.product_inventory
    SET quantity_available = v_new_wh, updated_at = now()
    WHERE product_id = v_item.product_id
      AND variant_id IS NOT DISTINCT FROM v_item.variant_id;

    INSERT INTO public.stock_movements
      (product_id, variant_id, delta, previous_quantity, new_quantity, reason, note, created_by)
    VALUES
      (v_item.product_id, v_item.variant_id, -v_item.quantity, v_prev_wh, v_new_wh, 'vendor_dispatch', 'Vendor order ' || p_vendor_order_id, p_created_by);

    SELECT quantity_available INTO v_prev_vendor
    FROM public.vendor_stock
    WHERE vendor_id = v_order.vendor_id
      AND product_id = v_item.product_id
      AND variant_id IS NOT DISTINCT FROM v_item.variant_id
    FOR UPDATE;

    IF NOT FOUND THEN
      v_prev_vendor := 0;
      INSERT INTO public.vendor_stock
        (store_id, vendor_id, product_id, variant_id, quantity_available, last_vendor_tp)
      VALUES
        (v_order.store_id, v_order.vendor_id, v_item.product_id, v_item.variant_id, v_item.quantity, v_item.vendor_tp);
      v_new_vendor := v_item.quantity;
    ELSE
      v_new_vendor := v_prev_vendor + v_item.quantity;
      UPDATE public.vendor_stock
      SET quantity_available = v_new_vendor, last_vendor_tp = v_item.vendor_tp, updated_at = now()
      WHERE vendor_id = v_order.vendor_id
        AND product_id = v_item.product_id
        AND variant_id IS NOT DISTINCT FROM v_item.variant_id;
    END IF;

    INSERT INTO public.vendor_stock_movements
      (vendor_id, product_id, variant_id, delta, previous_quantity, new_quantity, reason, reference_type, reference_id, created_by)
    VALUES
      (v_order.vendor_id, v_item.product_id, v_item.variant_id, v_item.quantity, v_prev_vendor, v_new_vendor, 'dispatch', 'vendor_order', p_vendor_order_id, p_created_by);
  END LOOP;

  UPDATE public.vendor_orders
  SET status = 'confirmed', confirmed_at = now(), updated_at = now()
  WHERE id = p_vendor_order_id;
END;
$$;
ALTER FUNCTION "public"."confirm_vendor_order"("uuid", "uuid") OWNER TO "postgres";
GRANT ALL ON FUNCTION "public"."confirm_vendor_order"("uuid", "uuid") TO "service_role";

-- -- record_vendor_settlement: sold/returned/payment in one transaction -
-- p_items is a JSON array of {product_id, variant_id, sold_quantity,
-- returned_quantity, unit_price}. unit_price is supplied by the caller
-- (defaults client-side to vendor_stock.last_vendor_tp but the owner may
-- override it per line -- necessary because a vendor's pooled stock can mix
-- goods dispatched at different vendor TPs over time).
CREATE OR REPLACE FUNCTION "public"."record_vendor_settlement"(
    "p_vendor_id" "uuid",
    "p_store_id" "uuid",
    "p_settlement_date" "date",
    "p_items" "jsonb",
    "p_payment_amount" numeric DEFAULT 0,
    "p_notes" "text" DEFAULT NULL,
    "p_created_by" "uuid" DEFAULT NULL
) RETURNS "uuid"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_settlement_id uuid;
  v_payment_id uuid;
  v_item jsonb;
  v_product_id uuid;
  v_variant_id uuid;
  v_sold integer;
  v_returned integer;
  v_unit_price numeric(10,2);
  v_prev_vendor integer;
  v_new_vendor integer;
  v_total_out integer;
  v_receivable numeric(12,2);
  v_total_receivable numeric(12,2) := 0;
  v_prev_wh integer;
  v_new_wh integer;
BEGIN
  IF jsonb_array_length(p_items) = 0 THEN
    RAISE EXCEPTION 'At least one settlement item is required';
  END IF;

  INSERT INTO public.vendor_settlements
    (store_id, vendor_id, settlement_date, notes, total_receivable, total_payment, created_by)
  VALUES
    (p_store_id, p_vendor_id, p_settlement_date, p_notes, 0, GREATEST(p_payment_amount, 0), p_created_by)
  RETURNING id INTO v_settlement_id;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_product_id := (v_item->>'product_id')::uuid;
    v_variant_id := NULLIF(v_item->>'variant_id', '')::uuid;
    v_sold := COALESCE((v_item->>'sold_quantity')::integer, 0);
    v_returned := COALESCE((v_item->>'returned_quantity')::integer, 0);
    v_unit_price := (v_item->>'unit_price')::numeric;
    v_total_out := v_sold + v_returned;

    IF v_total_out <= 0 THEN
      CONTINUE;
    END IF;

    SELECT quantity_available INTO v_prev_vendor
    FROM public.vendor_stock
    WHERE vendor_id = p_vendor_id
      AND product_id = v_product_id
      AND variant_id IS NOT DISTINCT FROM v_variant_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No vendor stock row for vendor % / product % / variant %', p_vendor_id, v_product_id, v_variant_id;
    END IF;

    IF v_prev_vendor < v_total_out THEN
      RAISE EXCEPTION 'Insufficient vendor stock for product %: have %, need %', v_product_id, v_prev_vendor, v_total_out;
    END IF;

    v_new_vendor := v_prev_vendor - v_total_out;

    UPDATE public.vendor_stock
    SET quantity_available = v_new_vendor, updated_at = now()
    WHERE vendor_id = p_vendor_id
      AND product_id = v_product_id
      AND variant_id IS NOT DISTINCT FROM v_variant_id;

    v_receivable := v_sold * v_unit_price;
    v_total_receivable := v_total_receivable + v_receivable;

    INSERT INTO public.vendor_settlement_items
      (settlement_id, product_id, variant_id, sold_quantity, returned_quantity, unit_price, receivable_amount)
    VALUES
      (v_settlement_id, v_product_id, v_variant_id, v_sold, v_returned, v_unit_price, v_receivable);

    IF v_sold > 0 THEN
      INSERT INTO public.vendor_stock_movements
        (vendor_id, product_id, variant_id, delta, previous_quantity, new_quantity, reason, reference_type, reference_id, created_by)
      VALUES
        (p_vendor_id, v_product_id, v_variant_id, -v_sold, v_prev_vendor, v_prev_vendor - v_sold, 'sold', 'vendor_settlement', v_settlement_id, p_created_by);
    END IF;

    IF v_returned > 0 THEN
      INSERT INTO public.vendor_stock_movements
        (vendor_id, product_id, variant_id, delta, previous_quantity, new_quantity, reason, reference_type, reference_id, created_by)
      VALUES
        (p_vendor_id, v_product_id, v_variant_id, -v_returned, v_prev_vendor - v_sold, v_new_vendor, 'returned', 'vendor_settlement', v_settlement_id, p_created_by);

      -- Auto-return: goods physically come back, so warehouse stock rises.
      SELECT quantity_available INTO v_prev_wh
      FROM public.product_inventory
      WHERE product_id = v_product_id
        AND variant_id IS NOT DISTINCT FROM v_variant_id
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'No warehouse inventory row for product % / variant %', v_product_id, v_variant_id;
      END IF;

      v_new_wh := v_prev_wh + v_returned;

      UPDATE public.product_inventory
      SET quantity_available = v_new_wh, updated_at = now()
      WHERE product_id = v_product_id
        AND variant_id IS NOT DISTINCT FROM v_variant_id;

      INSERT INTO public.stock_movements
        (product_id, variant_id, delta, previous_quantity, new_quantity, reason, note, created_by)
      VALUES
        (v_product_id, v_variant_id, v_returned, v_prev_wh, v_new_wh, 'vendor_return', 'Vendor settlement ' || v_settlement_id, p_created_by);
    END IF;
  END LOOP;

  UPDATE public.vendor_settlements
  SET total_receivable = v_total_receivable
  WHERE id = v_settlement_id;

  IF p_payment_amount > 0 THEN
    INSERT INTO public.vendor_payments
      (store_id, vendor_id, settlement_id, amount, payment_date, notes, created_by)
    VALUES
      (p_store_id, p_vendor_id, v_settlement_id, p_payment_amount, p_settlement_date, p_notes, p_created_by)
    RETURNING id INTO v_payment_id;
  END IF;

  RETURN v_settlement_id;
END;
$$;
ALTER FUNCTION "public"."record_vendor_settlement"("uuid", "uuid", "date", "jsonb", numeric, "text", "uuid") OWNER TO "postgres";
GRANT ALL ON FUNCTION "public"."record_vendor_settlement"("uuid", "uuid", "date", "jsonb", numeric, "text", "uuid") TO "service_role";


-- ============================================================
-- Source: supabase/migrations/20260712000000_add_vendor_tables_rls.sql
-- ============================================================
-- Row Level Security for the Vendor Distribution module.
--
-- The rest of this app (products, orders, product_inventory, expenses...)
-- has no RLS and relies entirely on application-level `.eq("store_id", ...)`
-- filtering, which is bypassable by anyone using the public anon key
-- directly against the Supabase REST API. Since vendor tables carry
-- financial data (dues, payments, receivables) and nothing yet depends on
-- them being unrestricted, they get locked down now while it's cheap.
--
-- Policy shape mirrors the one existing precedent in this schema --
-- "owner_read" on public.pixel_events -- which resolves the caller's store
-- via auth.uid() -> public.users.store_id and matches it against the row's
-- store_id. Tables that don't carry store_id directly (the *_items and
-- *_movements audit/line-item tables) join up to their parent row to reach
-- it instead.
--
-- Only SELECT policies are added. All writes to these tables already go
-- through supabaseAdmin (the service_role client) inside "use server"
-- functions and the confirm_vendor_order / record_vendor_settlement RPCs --
-- service_role bypasses RLS entirely, so those keep working unchanged.
-- With RLS enabled and no INSERT/UPDATE/DELETE policy for anon/authenticated,
-- direct writes from the browser's anon-key client are now denied by
-- default, which is the actual goal here.

ALTER TABLE "public"."vendors" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_stock" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_orders" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_order_items" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_settlements" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_settlement_items" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."vendor_payments" ENABLE ROW LEVEL SECURITY;
-- vendor_stock_movements already had RLS enabled in the prior migration
-- (mirroring stock_movements), with no policies -- i.e. already fully
-- locked down for anon/authenticated. Add the read policy here too so the
-- audit trail is at least viewable by the owning store.
ALTER TABLE "public"."vendor_stock_movements" ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "vendors_owner_select" ON "public"."vendors";
CREATE POLICY "vendors_owner_select" ON "public"."vendors" FOR SELECT TO "authenticated" USING (
  "store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
);

DROP POLICY IF EXISTS "vendor_stock_owner_select" ON "public"."vendor_stock";
CREATE POLICY "vendor_stock_owner_select" ON "public"."vendor_stock" FOR SELECT TO "authenticated" USING (
  "store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
);

DROP POLICY IF EXISTS "vendor_orders_owner_select" ON "public"."vendor_orders";
CREATE POLICY "vendor_orders_owner_select" ON "public"."vendor_orders" FOR SELECT TO "authenticated" USING (
  "store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
);

DROP POLICY IF EXISTS "vendor_settlements_owner_select" ON "public"."vendor_settlements";
CREATE POLICY "vendor_settlements_owner_select" ON "public"."vendor_settlements" FOR SELECT TO "authenticated" USING (
  "store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
);

DROP POLICY IF EXISTS "vendor_payments_owner_select" ON "public"."vendor_payments";
CREATE POLICY "vendor_payments_owner_select" ON "public"."vendor_payments" FOR SELECT TO "authenticated" USING (
  "store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
);

DROP POLICY IF EXISTS "vendor_order_items_owner_select" ON "public"."vendor_order_items";
CREATE POLICY "vendor_order_items_owner_select" ON "public"."vendor_order_items" FOR SELECT TO "authenticated" USING (
  "vendor_order_id" IN (
    SELECT "vendor_orders"."id" FROM "public"."vendor_orders"
    WHERE "vendor_orders"."store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
  )
);

DROP POLICY IF EXISTS "vendor_settlement_items_owner_select" ON "public"."vendor_settlement_items";
CREATE POLICY "vendor_settlement_items_owner_select" ON "public"."vendor_settlement_items" FOR SELECT TO "authenticated" USING (
  "settlement_id" IN (
    SELECT "vendor_settlements"."id" FROM "public"."vendor_settlements"
    WHERE "vendor_settlements"."store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
  )
);

DROP POLICY IF EXISTS "vendor_stock_movements_owner_select" ON "public"."vendor_stock_movements";
CREATE POLICY "vendor_stock_movements_owner_select" ON "public"."vendor_stock_movements" FOR SELECT TO "authenticated" USING (
  "vendor_id" IN (
    SELECT "vendors"."id" FROM "public"."vendors"
    WHERE "vendors"."store_id" IN (SELECT "users"."store_id" FROM "public"."users" WHERE "users"."id" = "auth"."uid"())
  )
);


-- ============================================================
-- Source: supabase/migrations/20260713000000_add_vendor_payment_method.sql
-- ============================================================
-- Adds a payment_method column to vendor_payments so the owner can record
-- *how* cash was collected from a vendor (COD, cash-in-hand, bKash/Nagad
-- under "mobile_banking", bank transfer, card) -- not just the amount.
-- Reuses the same value set as the existing public.orders payment_method
-- column (see src/lib/types/enums.ts PaymentMethod) rather than inventing a
-- new one, so the concept stays consistent across the app.
--
-- record_vendor_settlement gets a new trailing p_payment_method parameter.
-- CREATE OR REPLACE FUNCTION cannot change a function's argument list --
-- doing so creates a second, overloaded function instead of replacing the
-- original, which then makes PostgREST's RPC resolution ambiguous. The old
-- 7-argument signature is dropped explicitly first so only the new
-- 8-argument version exists afterward.

ALTER TABLE "public"."vendor_payments"
  ADD COLUMN IF NOT EXISTS "payment_method" character varying(30) DEFAULT 'cash' NOT NULL;

DO $$ BEGIN
  ALTER TABLE ONLY "public"."vendor_payments"
    ADD CONSTRAINT "vendor_payments_payment_method_check"
    CHECK (("payment_method")::"text" = ANY (ARRAY['cod'::"text", 'cash'::"text", 'online'::"text", 'card'::"text", 'bank_transfer'::"text", 'mobile_banking'::"text"]));
EXCEPTION WHEN duplicate_object OR duplicate_table THEN NULL; END $$;

DROP FUNCTION IF EXISTS "public"."record_vendor_settlement"("uuid", "uuid", "date", "jsonb", numeric, "text", "uuid");

CREATE OR REPLACE FUNCTION "public"."record_vendor_settlement"(
    "p_vendor_id" "uuid",
    "p_store_id" "uuid",
    "p_settlement_date" "date",
    "p_items" "jsonb",
    "p_payment_amount" numeric DEFAULT 0,
    "p_notes" "text" DEFAULT NULL,
    "p_created_by" "uuid" DEFAULT NULL,
    "p_payment_method" character varying DEFAULT 'cash'
) RETURNS "uuid"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_settlement_id uuid;
  v_payment_id uuid;
  v_item jsonb;
  v_product_id uuid;
  v_variant_id uuid;
  v_sold integer;
  v_returned integer;
  v_unit_price numeric(10,2);
  v_prev_vendor integer;
  v_new_vendor integer;
  v_total_out integer;
  v_receivable numeric(12,2);
  v_total_receivable numeric(12,2) := 0;
  v_prev_wh integer;
  v_new_wh integer;
BEGIN
  IF jsonb_array_length(p_items) = 0 THEN
    RAISE EXCEPTION 'At least one settlement item is required';
  END IF;

  INSERT INTO public.vendor_settlements
    (store_id, vendor_id, settlement_date, notes, total_receivable, total_payment, created_by)
  VALUES
    (p_store_id, p_vendor_id, p_settlement_date, p_notes, 0, GREATEST(p_payment_amount, 0), p_created_by)
  RETURNING id INTO v_settlement_id;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_product_id := (v_item->>'product_id')::uuid;
    v_variant_id := NULLIF(v_item->>'variant_id', '')::uuid;
    v_sold := COALESCE((v_item->>'sold_quantity')::integer, 0);
    v_returned := COALESCE((v_item->>'returned_quantity')::integer, 0);
    v_unit_price := (v_item->>'unit_price')::numeric;
    v_total_out := v_sold + v_returned;

    IF v_total_out <= 0 THEN
      CONTINUE;
    END IF;

    SELECT quantity_available INTO v_prev_vendor
    FROM public.vendor_stock
    WHERE vendor_id = p_vendor_id
      AND product_id = v_product_id
      AND variant_id IS NOT DISTINCT FROM v_variant_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No vendor stock row for vendor % / product % / variant %', p_vendor_id, v_product_id, v_variant_id;
    END IF;

    IF v_prev_vendor < v_total_out THEN
      RAISE EXCEPTION 'Insufficient vendor stock for product %: have %, need %', v_product_id, v_prev_vendor, v_total_out;
    END IF;

    v_new_vendor := v_prev_vendor - v_total_out;

    UPDATE public.vendor_stock
    SET quantity_available = v_new_vendor, updated_at = now()
    WHERE vendor_id = p_vendor_id
      AND product_id = v_product_id
      AND variant_id IS NOT DISTINCT FROM v_variant_id;

    v_receivable := v_sold * v_unit_price;
    v_total_receivable := v_total_receivable + v_receivable;

    INSERT INTO public.vendor_settlement_items
      (settlement_id, product_id, variant_id, sold_quantity, returned_quantity, unit_price, receivable_amount)
    VALUES
      (v_settlement_id, v_product_id, v_variant_id, v_sold, v_returned, v_unit_price, v_receivable);

    IF v_sold > 0 THEN
      INSERT INTO public.vendor_stock_movements
        (vendor_id, product_id, variant_id, delta, previous_quantity, new_quantity, reason, reference_type, reference_id, created_by)
      VALUES
        (p_vendor_id, v_product_id, v_variant_id, -v_sold, v_prev_vendor, v_prev_vendor - v_sold, 'sold', 'vendor_settlement', v_settlement_id, p_created_by);
    END IF;

    IF v_returned > 0 THEN
      INSERT INTO public.vendor_stock_movements
        (vendor_id, product_id, variant_id, delta, previous_quantity, new_quantity, reason, reference_type, reference_id, created_by)
      VALUES
        (p_vendor_id, v_product_id, v_variant_id, -v_returned, v_prev_vendor - v_sold, v_new_vendor, 'returned', 'vendor_settlement', v_settlement_id, p_created_by);

      -- Auto-return: goods physically come back, so warehouse stock rises.
      SELECT quantity_available INTO v_prev_wh
      FROM public.product_inventory
      WHERE product_id = v_product_id
        AND variant_id IS NOT DISTINCT FROM v_variant_id
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'No warehouse inventory row for product % / variant %', v_product_id, v_variant_id;
      END IF;

      v_new_wh := v_prev_wh + v_returned;

      UPDATE public.product_inventory
      SET quantity_available = v_new_wh, updated_at = now()
      WHERE product_id = v_product_id
        AND variant_id IS NOT DISTINCT FROM v_variant_id;

      INSERT INTO public.stock_movements
        (product_id, variant_id, delta, previous_quantity, new_quantity, reason, note, created_by)
      VALUES
        (v_product_id, v_variant_id, v_returned, v_prev_wh, v_new_wh, 'vendor_return', 'Vendor settlement ' || v_settlement_id, p_created_by);
    END IF;
  END LOOP;

  UPDATE public.vendor_settlements
  SET total_receivable = v_total_receivable
  WHERE id = v_settlement_id;

  IF p_payment_amount > 0 THEN
    INSERT INTO public.vendor_payments
      (store_id, vendor_id, settlement_id, amount, payment_date, notes, created_by, payment_method)
    VALUES
      (p_store_id, p_vendor_id, v_settlement_id, p_payment_amount, p_settlement_date, p_notes, p_created_by, COALESCE(p_payment_method, 'cash'))
    RETURNING id INTO v_payment_id;
  END IF;

  RETURN v_settlement_id;
END;
$$;
ALTER FUNCTION "public"."record_vendor_settlement"("uuid", "uuid", "date", "jsonb", numeric, "text", "uuid", character varying) OWNER TO "postgres";
GRANT ALL ON FUNCTION "public"."record_vendor_settlement"("uuid", "uuid", "date", "jsonb", numeric, "text", "uuid", character varying) TO "service_role";


-- ============================================================
-- Source: supabase/migrations/20260714000000_add_vendor_order_delivery_cost.sql
-- ============================================================
-- Adds an optional delivery_cost to vendor_orders. Not every dispatch has a
-- courier/vehicle fee, so it defaults to 0 and only shows up in the invoice
-- summary when the owner actually enters something. It's billed to the
-- vendor: grand_total = subtotal + delivery_cost - discount_amount.

ALTER TABLE "public"."vendor_orders"
  ADD COLUMN IF NOT EXISTS "delivery_cost" numeric(12,2) DEFAULT 0 NOT NULL;


-- ============================================================
-- Source: supabase/migrations/20260715000000_fix_dead_supabase_project_image_urls.sql
-- ============================================================
-- Fixes stored image URLs after a Supabase project migration.
--
-- Context: the project was migrated from the old Supabase project
-- (tzmrxxtrkwehdgzeyhgq.supabase.co, now deleted -- its hostname no longer
-- resolves) to the current one (sqvvtaejcfarmxcdvgrz.supabase.co). Storage
-- objects were copied over under the same bucket/path, but these text
-- columns still had the old hostname baked into the stored URL, so every
-- image referencing it 404s.
--
-- Verified before first running this: swapping just the hostname on a
-- broad sample of stored URLs (product images across multiple products,
-- plus all three stores' logo/banner URLs) resolved with HTTP 200 against
-- the new project, confirming the same bucket/path exists there.
-- categories.image_url, customer_profiles.avatar_url, and
-- user_profiles.avatar_url had zero rows on the old host, so they're not
-- included below -- add an UPDATE block for them the same way if that ever
-- changes.
--
-- Reusable for the next project migration: just change old_host/new_host
-- below and re-run. Safe to copy-paste and run again anytime -- the WHERE
-- clause only ever matches rows still pointing at old_host, so it's a
-- no-op once nothing does.

DO $$
DECLARE
  old_host CONSTANT text := 'https://tzmrxxtrkwehdgzeyhgq.supabase.co';
  new_host CONSTANT text := 'https://sqvvtaejcfarmxcdvgrz.supabase.co';
  updated_count integer;
BEGIN
  UPDATE "public"."product_images"
  SET "image_url" = replace("image_url", old_host, new_host)
  WHERE "image_url" LIKE '%' || old_host || '%';
  GET DIAGNOSTICS updated_count = ROW_COUNT;
  RAISE NOTICE 'product_images.image_url rows updated: %', updated_count;

  UPDATE "public"."stores"
  SET "logo_url" = replace("logo_url", old_host, new_host)
  WHERE "logo_url" LIKE '%' || old_host || '%';
  GET DIAGNOSTICS updated_count = ROW_COUNT;
  RAISE NOTICE 'stores.logo_url rows updated: %', updated_count;

  UPDATE "public"."stores"
  SET "banner_url" = replace("banner_url", old_host, new_host)
  WHERE "banner_url" LIKE '%' || old_host || '%';
  GET DIAGNOSTICS updated_count = ROW_COUNT;
  RAISE NOTICE 'stores.banner_url rows updated: %', updated_count;
END $$;

